    97	fn pipe_to_pager(output: &str) -> Result<()> {
    98	    use std::process::{Command, Stdio};
    99	
   100	    let pager = std::env::var("PAGER").unwrap_or_else(|_| "less".to_string());
   101	
   102	    let mut cmd = Command::new(&pager);
   103	    if pager == "less" || pager.ends_with("/less") {
   104	        // -R: pass ANSI codes through  -F: quit if output fits on one screen  -X: don't clear on exit
   105	        cmd.args(["-R", "-F", "-X"]);
   106	    }
   107	
   108	    match cmd.stdin(Stdio::piped()).spawn() {
   109	        Ok(mut child) => {
   110	            if let Some(mut stdin) = child.stdin.take() {
   111	                let _ = stdin.write_all(output.as_bytes());
   112	            }
   113	            child.wait()?;
   114	        }
   115	        Err(_) => print!("{}", output),
   116	    }
   117	    Ok(())
