+            sessions_with_signals,
+            avg_reprompt,
+            debug_loop_rate,
+            grade: grade_task_quality(avg_reprompt, debug_loop_rate),
+        });
+    }
+
+    rows.sort_by(|a, b| b.commits.cmp(&a.commits).then_with(|| a.task_key.cmp(&b.task_key)));
