fn fmt_opt_decimal(value: Option<f64>, precision: usize) -> String {
    match value {
        Some(v) => format!("{:.*}", precision, v),
        None => "N/A".to_string(),
    }
}

fn fmt_opt_percent(value: Option<f64>, precision: usize) -> String {
