fn evaluate_file_match_for_path(
    availability_stmt: &mut rusqlite::Statement<'_>,
    repo_root: &str,
    target_path: &str,
    rows: &[CommitHashRow],
) -> Result<PathMatch> {
    let mut out = PathMatch::default();

    for row in rows {
        let avail = load_session_availability(
            availability_stmt,
            repo_root,
            target_path,
            &row.side,
            &row.line_hash,
        )?;
        if avail.is_empty() {
            continue;
        }

        let avail_total: i64 = avail.iter().map(|a| a.avail).sum();
        if avail_total <= 0 {
            continue;
        }

        let matched = row.count.min(avail_total);
        if matched <= 0 {
            continue;
        }

        if row.side == "+" {
            out.matched_added += matched;
        } else if row.side == "-" {
            out.matched_removed += matched;
        }

        let matched_f = matched as f64;
        let avail_total_f = avail_total as f64;
        for availability in avail {
            let contribution = matched_f * (availability.avail as f64 / avail_total_f);
            *out.provider_matched
                .entry(availability.provider.clone())
                .or_insert(0.0) += contribution;
            *out.session_matched
                .entry((availability.provider, availability.session_id))
                .or_insert(0.0) += contribution;
        }
    }

    Ok(out)
}

