fn cursor_vscdb_path() -> Result<PathBuf> {
    // macOS
    #[cfg(target_os = "macos")]
    {
        let home = dirs::home_dir().ok_or_else(|| anyhow::anyhow!("Home directory not found"))?;
        let p = home
            .join("Library")
            .join("Application Support")
            .join("Cursor")
            .join("User")
            .join("globalStorage")
            .join("state.vscdb");
        if p.exists() {
            return Ok(p);
        }
    }

    // Linux
    let home = dirs::home_dir().ok_or_else(|| anyhow::anyhow!("Home directory not found"))?;
    let p = home
        .join(".config")
        .join("Cursor")
        .join("User")
        .join("globalStorage")
        .join("state.vscdb");
    if p.exists() {
        return Ok(p);
    }

    anyhow::bail!("Cursor state.vscdb not found on macOS or Linux paths")
}

