/// Convert millisecond epoch to ISO-8601 string.
fn ms_to_iso(ms: i64) -> String {
    let secs = ms / 1000;
    match chrono::Utc.timestamp_opt(secs, 0) {
        chrono::LocalResult::Single(dt) => dt.to_rfc3339(),
        _ => format!("{}", ms),
    }
}

