   420	fn load_session_messages(conn: &Connection) -> Result<BTreeMap<SessionKey, Vec<SessionMessage>>> {
   421	    let mut stmt = conn.prepare(
   422	        "SELECT provider, session_id, role, content
   423	         FROM events
   424	         WHERE event_type = 'message'
   425	           AND role IN ('user', 'assistant')
   426	         ORDER BY provider, session_id, COALESCE(event_ts, session_started_at), id",
   427	    )?;
   428	
   429	    let rows = stmt.query_map([], |r| {
   430	        Ok((
   431	            r.get::<_, String>(0)?,
   432	            r.get::<_, String>(1)?,
   433	            r.get::<_, String>(2)?,
   434	            r.get::<_, String>(3)?,
   435	        ))
   436	    })?;
   437	
   438	    let mut sessions: BTreeMap<SessionKey, Vec<SessionMessage>> = BTreeMap::new();
   439	    for row in rows {
   440	        let (provider, session_id, role, content) = row?;
   441	        sessions
   442	            .entry(SessionKey {
   443	                provider,
   444	                session_id,
   445	            })
   446	            .or_default()
   447	            .push(SessionMessage { role, content });
   448	    }
   449	    Ok(sessions)
   450	}
