   452	fn build_session_turns(messages: &[SessionMessage]) -> Vec<SessionTurn> {
   453	    let mut turns = Vec::new();
   454	    let mut current_user: Option<String> = None;
   455	    let mut assistant_parts: Vec<&str> = Vec::new();
   456	
   457	    for message in messages {
   458	        match message.role.as_str() {
   459	            "user" => {
   460	                if let Some(user_text) = current_user.take() {
   461	                    turns.push(SessionTurn {
   462	                        user_text,
   463	                        assistant_text: assistant_parts.join("\n"),
   464	                    });
   465	                    assistant_parts.clear();
   466	                }
   467	                current_user = Some(message.content.clone());
   468	            }
   469	            "assistant" => {
   470	                if current_user.is_some() {
   471	                    assistant_parts.push(message.content.as_str());
   472	                }
   473	            }
   474	            _ => {}
   475	        }
   476	    }
   477	
   478	    if let Some(user_text) = current_user {
   479	        turns.push(SessionTurn {
   480	            user_text,
   481	            assistant_text: assistant_parts.join("\n"),
   482	        });
   483	    }
   484	
   485	    turns
   486	}
